// Code Node: Medical Classification with OCR Enhancement
const items = $input.all();
return items.map((item, index) => {
    const text = item.json.text || ''; 

    // Advanced classification logic
    let pageType = 'Note';
    if (text.match(/\b(CBC|BMP|CMP|Lipid Panel|HbA1c)\b/i)) {
        pageType = 'Lab';
    } else if (text.match(/\b(Prescription|Medication|Rx|Dosage)\b/i)) {
        pageType = 'Rx';
    } else if (text.match(/\b(X-Ray|MRI|CT Scan|Ultrasound|Radiology)\b/i)) {
        pageType = 'Imaging';
    } else if (text.match(/\b(Progress Note|SOAP|Assessment|Plan)\b/i)) {
        pageType = 'Clinical Note';
    }

    item.json.pageType = pageType;
    item.json.pageHash = 'SHA256-' + Buffer.from(text).toString('base64').substring(0, 16);
    item.json.processedAt = new Date().toISOString();
    item.json.pageNumber = index + 1;

    // Flag sensitive sections
    item.json.hasPII = text.match(/\b(SSN|DOB|Phone|Address)\b/i) ? true : false;

    return item;
});

// Code Node: Advanced PII Scrubbing (HIPAA-compliant)
const item = $input.first().json;

// Comprehensive redaction patterns
const redactionPatterns = [
    { pattern: /\b\d{3}-\d{2}-\d{4}\b/g, label: '[SSN-REDACTED]' },
    { pattern: /\b\d{10}\b/g, label: '[PHONE-REDACTED]' },
    { pattern: /\b[A-Z][a-z]+ [A-Z][a-z]+\b/g, label: '[NAME-REDACTED]' },
    { pattern: /Technician: [A-Za-z ]+/g, label: '[TECH-REDACTED]' },
    { pattern: /\b\d{1,5}\s\w+\s(Street|St|Avenue|Ave|Road|Rd|Boulevard|Blvd)\b/gi, label: '[ADDRESS-REDACTED]' },
    { pattern: /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, label: '[EMAIL-REDACTED]' },
    { pattern: /\b(\d{2}\/\d{2}\/\d{4})\b/g, label: '[DOB-REDACTED]' }
];

let sanitizedText = item.text || '';
let redactionCount = 0;

redactionPatterns.forEach(({ pattern, label }) => {
    const matches = sanitizedText.match(pattern);
    if (matches) {
        redactionCount += matches.length;
        sanitizedText = sanitizedText.replace(pattern, label);
    }
});

item.sanitizedText = sanitizedText;
item.redactionCount = redactionCount;
item.sanitizedAt = new Date().toISOString();
item.complianceStatus = redactionCount > 0 ? 'PII_REMOVED' : 'CLEAN';

return { json: item };

// Code Node: Anomaly Detection
const item = $input.first().json;
const text = item.sanitizedText || '';

// Flag critical values or concerning patterns
const anomalies = [];

// Lab value checks
if (text.match(/glucose.*?(\d{3,})/i)) {
    anomalies.push({ type: 'HIGH_GLUCOSE', severity: 'HIGH' });
}
if (text.match(/blood pressure.*?(\d{3}\/\d{3})/i)) {
    anomalies.push({ type: 'HYPERTENSION', severity: 'MEDIUM' });
}
if (text.match(/\b(critical|urgent|stat|emergency)\b/i)) {
    anomalies.push({ type: 'URGENT_FLAG', severity: 'CRITICAL' });
}

item.anomalies = anomalies;
item.requiresReview = anomalies.some(a => a.severity === 'CRITICAL');
item.anomalyCount = anomalies.length;

return { json: item };

